import{_ as a,c as t,a1 as e,o as h}from"./chunks/framework.BDxlaA_J.js";const m=JSON.parse('{"title":"Công cụ Sniffing Windows","description":"","frontmatter":{},"headers":[],"relativePath":"vi/categories/ethical-hacking-labs/7-sniffing/X-Windows-Tools.md","filePath":"vi/categories/ethical-hacking-labs/7-sniffing/X-Windows-Tools.md"}'),i={name:"vi/categories/ethical-hacking-labs/7-sniffing/X-Windows-Tools.md"};function r(c,n,o,s,p,g){return h(),t("div",null,n[0]||(n[0]=[e('<h1 id="cong-cu-sniffing-windows" tabindex="-1">Công cụ Sniffing Windows <a class="header-anchor" href="#cong-cu-sniffing-windows" aria-label="Permalink to &quot;Công cụ Sniffing Windows&quot;">​</a></h1><h2 id="wireshark" tabindex="-1">Wireshark <a class="header-anchor" href="#wireshark" aria-label="Permalink to &quot;Wireshark&quot;">​</a></h2><p>Wireshark là trình phân tích giao thức mạng hàng đầu và được sử dụng rộng rãi nhất trên thế giới. Nó cho phép bạn xem những gì đang xảy ra trên mạng ở cấp độ vi mô và là tiêu chuẩn thực tế (và thường là tiêu chuẩn pháp lý) trong nhiều doanh nghiệp thương mại và phi lợi nhuận, cơ quan chính phủ và tổ chức giáo dục.</p><p><a href="https://www.wireshark.org/" target="_blank" rel="noreferrer">https://www.wireshark.org/</a></p><h2 id="cain-abel" tabindex="-1">Cain &amp; Abel <a class="header-anchor" href="#cain-abel" aria-label="Permalink to &quot;Cain &amp; Abel&quot;">​</a></h2><p>Cain &amp; Abel là công cụ bảo mật rất hữu ích được sử dụng để giải mã và giải mật khẩu cho nhiều chương trình ngoại tuyến và dịch vụ mạng khác nhau. Được xây dựng từ đầu để cực kỳ hữu ích cho người dùng đã quên mật khẩu cho một số ứng dụng được sử dụng nhiều nhất trên PC tại nhà, Cain và Abel có các thuật toán giải mã mạnh mẽ, công cụ giải mã mở rộng, và nhiều hơn nữa.</p><p><a href="https://www.filehorse.com/download-cain-and-abel/" target="_blank" rel="noreferrer">https://www.filehorse.com/download-cain-and-abel/</a></p><p><img src="https://1.bp.blogspot.com/-Cu3iqrOhY8A/TZ7vKOfWMfI/AAAAAAAABkc/xeaZvXMNKCg/s728-e100/537.jpg" alt="cainable"></p><h2 id="smac" tabindex="-1">SMAC <a class="header-anchor" href="#smac" aria-label="Permalink to &quot;SMAC&quot;">​</a></h2><p>SMAC là công cụ mạnh mẽ và dễ sử dụng để thay đổi địa chỉ MAC (spoofer). Công cụ có thể kích hoạt địa chỉ MAC mới ngay sau khi thay đổi tự động.</p><p><a href="https://smac.soft32.com/" target="_blank" rel="noreferrer">https://smac.soft32.com/</a></p><p><img src="https://thegeekpage.com/wp-content/uploads/2016/05/mac-address-changer-tool.gif" alt="smac"></p><h2 id="capsa-network-analyzer" tabindex="-1">Capsa Network Analyzer <a class="header-anchor" href="#capsa-network-analyzer" aria-label="Permalink to &quot;Capsa Network Analyzer&quot;">​</a></h2><p>Capsa Free là trình phân tích mạng miễn phí cho giám sát Ethernet, khắc phục sự cố và phân tích. Nó cung cấp cho người dùng trải nghiệm tuyệt vời để học cách giám sát hoạt động mạng, xác định sự cố mạng, nâng cao bảo mật mạng. <a href="https://www.colasoft.com/capsa-free/" target="_blank" rel="noreferrer">https://www.colasoft.com/capsa-free/</a></p><p><img src="https://www.colasoft.com/images/capsa-8-screenshots/home-dashboard.jpg" alt="capsa"></p><h2 id="omnipeek" tabindex="-1">OmniPeek <a class="header-anchor" href="#omnipeek" aria-label="Permalink to &quot;OmniPeek&quot;">​</a></h2><p>Omnipeek cung cấp phân tích thời gian thực cho mọi loại phân khúc mạng, 802.11, và thoại và video qua IP và cho mọi cấp độ lưu lượng mạng.</p><p><a href="https://www.liveaction.com/products/omnipeek-network-protocol-analyzer/" target="_blank" rel="noreferrer">https://www.liveaction.com/products/omnipeek-network-protocol-analyzer/</a></p><h2 id="xarp-phat-hien-arp-spoofing" tabindex="-1">XArp - Phát hiện ARP Spoofing <a class="header-anchor" href="#xarp-phat-hien-arp-spoofing" aria-label="Permalink to &quot;XArp - Phát hiện ARP Spoofing&quot;">​</a></h2><p>XArp là ứng dụng bảo mật sử dụng các kỹ thuật tiên tiến để phát hiện các cuộc tấn công dựa trên ARP. Sử dụng các module chủ động và thụ động, XArp phát hiện hacker bên trong mạng của bạn. Tấn công ARP cho phép kẻ tấn công nghe trộm hoặc thao tác im lặng tất cả dữ liệu được gửi qua mạng. Bao gồm tài liệu, email, hoặc cuộc trò chuyện VoiceIP. Tấn công ARP spoofing không bị phát hiện bởi firewall và bảo mật hệ điều hành: Firewall không bảo vệ bạn chống lại tấn công dựa trên ARP.</p><p><a href="http://www.xarp.net/" target="_blank" rel="noreferrer">http://www.xarp.net/</a></p><p><img src="https://qpdownload.com/data/xarp/screenshot/xarp_screenshot_normal_view.png" alt="xarp"></p>',22)]))}const d=a(i,[["render",r]]);export{m as __pageData,d as default};
